patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..2d8989cb30b7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2016,6 +2016,47 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
                           ConstantInt::get(MaskA->getType(), NewComperand));
     }
   }
+  // if higher bits of X are known zero.
+  {
+    Value *A;
+    const APInt *Addend, *Mask;
+    if (Cmp.isEquality() && C.isZero() &&
+        match(And, m_c_And(m_OneUse(m_Add(m_Value(A), m_APInt(Addend))),
+                           m_APInt(Mask))) &&
+        Addend->isAllOnes() && Mask->getBitWidth() > 1) {
+      APInt NotMask = ~*Mask;
+      if (NotMask.isPowerOf2() && NotMask.countTrailingZeros() == 1) { // only bit 1 cleared
+        unsigned BitWidth = Mask->getBitWidth();
+        APInt HighBitsMask = APInt::getHighBitsSet(BitWidth, BitWidth - 2);
+        // Check via known bits.
+        KnownBits Known = computeKnownBits(A, &Cmp, 0);
+        bool HighBitsZero = (Known.Zero & HighBitsMask) == HighBitsMask;
+        // Check via argument range attribute.
+        if (!HighBitsZero) {
+          if (auto *Arg = dyn_cast<Argument>(A)) {
+            if (auto OptCR = Arg->getRange()) {
+              ConstantRange CR = *OptCR;
+              HighBitsZero = CR.getUnsignedMax().ult(APInt::getOneBitSet(BitWidth, BitWidth - 2));
+            }
+          }
+        }
+        // Check via constant range.
+        if (!HighBitsZero) {
+          ConstantRange CR = computeConstantRange(A, /*ForSigned=*/false);
+          HighBitsZero = CR.getUnsignedMax().ult(APInt::getOneBitSet(BitWidth, BitWidth - 2));
+        }
+        if (HighBitsZero) {
+          // Transform.
+          Value *NewAnd = Builder.CreateAnd(A, ConstantInt::get(A->getType(), 1));
+          auto NewPred = Cmp.getPredicate() == ICmpInst::ICMP_EQ ?
+                         ICmpInst::ICMP_NE : ICmpInst::ICMP_EQ;
+          return new ICmpInst(NewPred, NewAnd,
+                              ConstantInt::getNullValue(NewAnd->getType()));
+        }
+      }
+    }
+  }
+

   return nullptr;
 }

